#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y, Z;
        scanf("%lld %lld %lld", &X, &Y, &Z);
        long long costPerWall = 2LL * X * Y;
        long long ans = Z / costPerWall;
        printf("%lld\n", ans);
    }
    return 0;
}

