#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        cost = 2 * X * Y
        out.append(str(Z // cost))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

